def fill_multi_step_form(page, steps_data):
    for step_num, fields in enumerate(steps_data, 1):
        print(f'Paso {step_num}...')
        for selector, value in fields.items():
            field = page.locator(selector)
            field.wait_for(state='visible', timeout=5000)
            if field.evaluate('el => el.type') == 'checkbox':
                if value:
                    field.check()
            elif field.evaluate('el => el.tagName') == 'SELECT':
                field.select_option(value)
            else:
                field.fill(str(value))

        # Click Next/Continue
        next_btn = page.locator('button:has-text("Next"), button:has-text("Continue")')
        if next_btn.count() > 0 and next_btn.first.is_visible():
            next_btn.first.click()
            page.wait_for_timeout(500)

    # Submit final
    page.locator('button:has-text("Submit"), button[type="submit"]').click()

fill_multi_step_form(page, [
    {'#name': 'Nestor', '#email': 'nestor@gbm.net'},
    {'#company': 'GBM', '#phone': '+502555'},
    {'#plan': 'Premium', '#terms': True},
])
